mapper.select:
SELECT CUST.CUST_CD, CUST.CUST_NM ,CUST.IRS_NUM AS IRS_NO ,CUST.CEO_USER_NM AS CEO_USER_NM ,CUST.COMPANY_TYPE ,CUST.CORP_TYPE ,CUST.SCALE_TYPE ,CUST.BUSINESS_TYPE ,CUST.INDUSTRY_TYPE ,CUST.TEL_NUM AS TEL_NUM ,CUST.STOP_FLAG ,(CUST.REG_DATE, 'yyyyMMdd') AS REG_DATE ,(CUST.MOD_DATE, 'yyyyMMdd') AS MOD_DATE ,GETUSERNAME(CUST.GATE_CD, CUST.MOD_USER_ID, #{ses.langCd}) AS MOD_USER_NM ,CUST.MOD_USER_ID ,CUST.PROGRESS_CD ,CUST.RELAT_YN ,((SELECT MAX(SEQ) FROM STOCCUSH WHERE GATE_CD = CUST.GATE_CD AND CUST_CD = CUST.CUST_CD AND SEQ > 0), '0') AS CHANGE_CNT FROM STOCCUST CUST WHERE CUST.GATE_CD = #{ses.gateCd} AND CUST.DEL_FLAG = '0'
AND UPPER(CUST.CUST_CD) LIKE '%' UPPER(#{CUST_CD}) '%'
AND UPPER(CUST.CUST_NM) LIKE '%' UPPER(#{CUST_NM}) '%'
AND CUST.COMPANY_TYPE = #{COMPANY_TYPE}
AND CUST.CORP_TYPE = #{CORP_TYPE}
AND CUST.RELAT_YN = #{RELAT_YN}
AND REPLACE(CUST.IRS_NUM, '-', '') LIKE '%' REPLACE(#{IRS_NO}, '-', '') '%'
AND UPPER(CUST.CEO_USER_NM) LIKE '%' UPPER(#{CEO_USER_NM}) '%'
ORDER BY CUST.CUST_CD

