INSERT INTO STOCCUSH (
	  GATE_CD
	, CUST_CD
	, SEQ
	, REG_DATE
	, REG_USER_ID
	, MOD_DATE
	, MOD_USER_ID
	, DEL_FLAG
	, CEO_USER_NM
	, ZIP_CD
	, ADDR_1
	, ADDR_2
	, CH_DATE
	, CH_USER_ID
)
VALUES (
	  #{ses.gateCd}
	, #{CUST_CD}
	, ((SELECT MAX(SEQ)+1 FROM STOCCUSH WHERE GATE_CD = #{ses.gateCd} AND CUST_CD = #{CUST_CD}), 0)
	, SYSDATE
	, #{ses.userId}
	, SYSDATE
	, #{ses.userId}
	, '0'
	, #{CEO_USER_NM}
	, #{HQ_ZIP_CD}
	, #{HQ_ADDR_1}
	, #{HQ_ADDR_2}
	, SYSDATE
	, #{ses.userId}
)

mapper.select:
SELECT OGDP.DEPT_CD ,OGDP.DEPT_CD AS HIDDEN_DEPT_CD ,OGDP.DEPT_NM ,OGDP.PARENT_DEPT_CD ,(CASE WHEN (OGDP.DEL_FLAG, '0') = '0' THEN '1' ELSE '0' END) AS DEL_FLAG ,OGDP.DEPT_TYPE ,OGDP.SEQ ,OGDP.ZIP_CD AS ZIP_CD ,OGDP.ADDR1 AS ADDR1 ,OGDP.ADDR2 AS ADDR2 ,OGDP.PARENT_DEPT_CD ,(CASE WHEN OGDP.LVL = '1' THEN (getBuyerInfo(OGDP.GATE_CD, OGDP.BUYER_CD, 'CUST_NM'), getBuyerName(OGDP.GATE_CD, OGDP.BUYER_CD, #{ses.langCd})) ELSE (SELECT A.DEPT_NM FROM STOCOGDP A WHERE A.GATE_CD = OGDP.GATE_CD AND A.BUYER_CD = OGDP.BUYER_CD AND A.DEPT_CD = OGDP.PARENT_DEPT_CD) END) AS PARENT_DEPT_NM FROM STOCOGDP OGDP WHERE OGDP.GATE_CD = #{ses.gateCd} AND OGDP.DEPT_TYPE = #{DEPT_TYPE} AND OGDP.BUYER_CD = #{CUST_CD}
AND OGDP.PARENT_DEPT_CD = #{PARENT_DEPT_CD}
AND UPPER(OGDP.DEPT_NM) LIKE '%' UPPER(#{DEPT_NM}) '%'
ORDER BY TO_NUMBER(OGDP.SEQ), OGDP.LVL, OGDP.DEPT_NM
ORDER BY convert(numeric, OGDP.SEQ), OGDP.LVL, OGDP.DEPT_NM

SELECT OGDP.DEPT_CD ,OGDP.DEPT_CD AS HIDDEN_DEPT_CD ,OGDP.DEPT_NM ,OGDP.PARENT_DEPT_CD ,(CASE WHEN OGDP.PARENT_DEPT_CD = '1000' THEN (SELECT A.BUYER_NM FROM STOCOGCM A WHERE A.GATE_CD = OGDP.GATE_CD AND A.BUYER_CD = OGDP.PARENT_DEPT_CD) ELSE (SELECT A.DEPT_NM FROM STOCOGDP A WHERE A.GATE_CD = OGDP.GATE_CD AND A.BUYER_CD = OGDP.BUYER_CD AND A.DEPT_CD = OGDP.PARENT_DEPT_CD) END) AS PARENT_DEPT_NM ,(CASE WHEN (OGDP.DEL_FLAG, '0') = '0' THEN '1' ELSE '0' END) AS DEL_FLAG ,OGDP.DEPT_TYPE ,OGDP.SEQ ,OGDP.ZIP_CD AS ZIP_CD ,OGDP.ADDR1 AS ADDR1 ,OGDP.ADDR2 AS ADDR2 FROM STOCOGDP OGDP WHERE OGDP.GATE_CD = #{ses.gateCd} AND OGDP.BUYER_CD = #{ses.companyCd} AND OGDP.DEPT_TYPE = #{DEPT_TYPE}
AND OGDP.PARENT_DEPT_CD = #{PARENT_DEPT_CD}
AND UPPER(OGDP.DEPT_NM) LIKE '%' UPPER(#{DEPT_NM}) '%'
OR OGDP.DEPT_CD IN (SELECT OGDP.PARENT_DEPT_CD FROM STOCOGDP OGDP WHERE OGDP.GATE_CD = #{ses.gateCd} AND OGDP.BUYER_CD = #{ses.companyCd} AND OGDP.DEPT_TYPE = '300' AND OGDP.DEL_FLAG = '0' AND UPPER(OGDP.DEPT_NM) LIKE '%' UPPER(#{DEPT_NM}) '%')
OR OGDP.DEPT_CD IN (SELECT T.PARENT_DEPT_CD FROM STOCOGDP T WHERE T.GATE_CD = #{ses.gateCd} AND T.BUYER_CD = #{ses.companyCd} AND T.DEPT_TYPE = '200' AND T.DEL_FLAG = '0' AND T.DEPT_CD IN (SELECT OGDP.PARENT_DEPT_CD FROM STOCOGDP OGDP WHERE OGDP.GATE_CD = #{ses.gateCd} AND OGDP.BUYER_CD = #{ses.companyCd} AND OGDP.DEPT_TYPE ='300' AND OGDP.DEL_FLAG = '0' AND UPPER(OGDP.DEPT_NM) LIKE '%' UPPER(#{DEPT_NM}) '%')) OR OGDP.DEPT_CD IN (SELECT T.PARENT_DEPT_CD FROM STOCOGDP T WHERE T.GATE_CD = #{ses.gateCd} AND T.BUYER_CD = #{ses.companyCd} AND T.DEPT_TYPE = '200' AND T.DEL_FLAG = '0' AND UPPER(T.DEPT_NM) LIKE '%' UPPER(#{DEPT_NM}) '%')
ORDER BY OGDP.LVL, OGDP.DEPT_NM

SELECT COUNT(A.DEPT_CD) AS CNT
  FROM STOCOGDP A
 WHERE A.GATE_CD = #{ses.gateCd}
   AND A.BUYER_CD = #{CUST_CD}
   AND A.DEL_FLAG = '0'
   AND A.DEPT_CD = (CASE WHEN #{HIDDEN_DEPT_CD} = '' THEN #{DEPT_CD} ELSE (CASE WHEN #{HIDDEN_DEPT_CD} = #{DEPT_CD} THEN NULL ELSE #{DEPT_CD} END) END)

mapper.insert:
MERGE  STOCOGDP OGDP
USING (SELECT #{ses.gateCd} AS GATE_CD
			 ,#{CUST_CD} AS BUYER_CD
			 ,#{DEPT_CD} AS DEPT_CD
		 ) B
 ON (OGDP.GATE_CD = B.GATE_CD
 AND OGDP.BUYER_CD = B.BUYER_CD
 AND OGDP.DEPT_CD = B.DEPT_CD)
WHEN MATCHED THEN
UPDATE SET
	  MOD_USER_ID = #{ses.userId}
	, MOD_DATE = SYSDATE
	, DEL_FLAG = (CASE WHEN #{DEL_FLAG} = '1' THEN '0' ELSE '1' END)
	, DEPT_NM = #{DEPT_NM}
	, PARENT_DEPT_CD = #{PARENT_DEPT_CD}
	, DEPT_TYPE = #{DEPT_TYPE}
	, LVL = #{LVL}
	, SEQ = #{SEQ}
	, ZIP_CD = #{ZIP_CD}
	, ADDR1 = #{ADDR1}
	, ADDR2 = #{ADDR2}
WHEN NOT MATCHED THEN
INSERT (
	  GATE_CD
	, BUYER_CD
	, DEPT_CD
	, REG_USER_ID
	, MOD_USER_ID
	, DEL_FLAG
	, DEPT_NM
	, PARENT_DEPT_CD
	, DEPT_TYPE
	, LVL
	, SEQ
	, REG_DATE
	, MOD_DATE
	, ZIP_CD
	, ADDR1
	, ADDR2
) VALUES (
	  #{ses.gateCd}
	, #{CUST_CD}
	, #{DEPT_CD}
	, #{ses.userId}
	, #{ses.userId}
	, (CASE WHEN #{DEL_FLAG} = '1' THEN '0' ELSE '1' END)
	, #{DEPT_NM}
	, #{PARENT_DEPT_CD}
	, #{DEPT_TYPE}
	, #{LVL}
	, (SELECT NVL(MAX(SEQ) + 1, 1) FROM STOCOGDP WHERE GATE_CD = #{ses.gateCd} AND BUYER_CD = #{CUST_CD} AND PARENT_DEPT_CD = #{PARENT_DEPT_CD})
	, SYSDATE
	, SYSDATE
	, #{ZIP_CD}
	, #{ADDR1}
	, #{ADDR2}
)

MERGE  STOCOGDA OGDA
USING (SELECT #{ses.gateCd} AS GATE_CD
			 ,#{CUST_CD} AS BUYER_CD
			 ,#{DEPT_CD} AS DEPT_CD
			 ,#{ACCOUNT_SQ} AS ACCOUNT_SQ
		 ) B
 ON (OGDA.GATE_CD = B.GATE_CD
 AND OGDA.BUYER_CD = B.BUYER_CD
 AND OGDA.DEPT_CD = B.DEPT_CD
 AND OGDA.ACCOUNT_SQ = B.ACCOUNT_SQ)
WHEN MATCHED THEN
UPDATE SET
	  MOD_USER_ID = #{ses.userId}
	, MOD_DATE = SYSDATE
	, DEL_FLAG = #{DEL_FLAG}
	, USE_FLAG = #{USE_FLAG}
	, BANK_NM = #{BANK_NM}
	, BANK_BRANCH_OFFICE = #{BANK_BRANCH_OFFICE}
	, BANK_ACCT_NUM = #{BANK_ACCT_NUM}
	, ACCT_HOLDER_NM = #{ACCT_HOLDER_NM}
	, ACCT_NICKNAME = #{ACCT_NICKNAME}
	, ATTACH_FILE_NUM = #{ATTACH_FILE_NUM}
WHEN NOT MATCHED THEN
INSERT (
	  GATE_CD
	, BUYER_CD
	, DEPT_CD
	, ACCOUNT_SQ
	, REG_USER_ID
	, REG_DATE
	, MOD_USER_ID
	, MOD_DATE
	, DEL_FLAG
	, USE_FLAG
	, BANK_NM
	, BANK_BRANCH_OFFICE
	, BANK_ACCT_NUM
	, ACCT_HOLDER_NM
	, ACCT_NICKNAME
	, ATTACH_FILE_NUM
) VALUES (
	  #{ses.gateCd}
	, #{CUST_CD}
	, #{DEPT_CD}
	, (SELECT NVL(MAX(ACCOUNT_SQ) + 1, 1) FROM STOCOGDA WHERE GATE_CD = #{ses.gateCd} AND BUYER_CD = #{CUST_CD} AND DEPT_CD = #{DEPT_CD})
	, #{ses.userId}
	, SYSDATE
	, #{ses.userId}
	, SYSDATE
	, #{DEL_FLAG}
	, #{USE_FLAG}
	, #{BANK_NM}
	, #{BANK_BRANCH_OFFICE}
	, #{BANK_ACCT_NUM}
	, #{ACCT_HOLDER_NM}
	, #{ACCT_NICKNAME}
	, #{ATTACH_FILE_NUM}
)

